import json

def merge_jsonl_files(paths):
    latest = {}

    for path in paths:
        with open(path, "r") as file_obj:
            for line in file_obj:
                line = line.strip()
                if not line:
                    continue
                record = json.loads(line)
                latest[record["id"]] = record

    return [latest[key] for key in latest]
